"use client";

import { useState } from "react";
import { useForm, FieldValues } from "react-hook-form";

import { Form } from "@/components/ui/form";
import { Button } from "@/components/ui/button";
import { DynamicFormField } from "@/components/forms/form-field";
import ReCAPTCHAComponent from "@/components/forms/form-ui/form-utils/ReCAPTCHAComponent";

import type { FormBuilderStandardProps, SectionLayout } from "./types";
import { typedZodResolver } from "@/lib/utils/typedZodResolver";
import { FieldSeparator } from "@/components/ui/field";
import { cn } from "@/lib/utils";

export function FormBuilderStandard<T extends FieldValues>({
  schema,
  defaultValues,
  formType = "CREATE",
  sections,
  buttons,
  buttonLayout = "stack",
  recaptcha = false,
  className,
}: FormBuilderStandardProps<T>) {
  const form = useForm<T>({
    resolver: typedZodResolver(schema),
    defaultValues,
  });

  const isSubmitting = form.formState.isSubmitting;
  const [captchaToken, setCaptchaToken] = useState<string | null>(null);
  const [activeButton, setActiveButton] = useState<string | null>(null);

  /**
   * NOTE:
   * buttonKey is passed directly — NOT read from state
   */
  const handleSubmit = (buttonKey: string | null) => async (values: T) => {
    if (formType === "VIEW") return;
    if (recaptcha && !captchaToken) return;
    if (!buttonKey) return;

    const button = buttons[buttonKey];
    if (!button?.onSubmit) return;

    await button.onSubmit(values, form);

    if (formType === "CREATE") {
      form.reset(defaultValues);
    }
  };

  /* --------------------------------------------------
   * SECTION LAYOUT HELPER
   * -------------------------------------------------- */
  function getSectionLayoutClass(layout?: SectionLayout, columns?: number) {
    switch (layout) {
      case "grid-2":
        return "grid grid-cols-1 sm:grid-cols-2 gap-4";

      case "grid-3":
        return "grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4";

      case "grid-4":
        return "grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4";

      case "grid-6":
        return "grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-6 gap-4";

      case "auto-fit":
        return "grid [grid-template-columns:repeat(auto-fit,minmax(240px,1fr))] gap-4";

      case "grid": {
        const c = Math.min(Math.max(columns ?? 2, 1), 6);
        return `grid grid-cols-1 sm:grid-cols-${Math.min(
          c,
          2
        )} lg:grid-cols-${c} gap-4`;
      }

      default:
        return "flex flex-col gap-5";
    }
  }

  /* --------------------------------------------------
   * BUTTON LAYOUT
   * -------------------------------------------------- */

  const buttonLayoutClass =
    buttonLayout === "stack"
      ? "flex flex-col gap-3"
      : buttonLayout === "right"
      ? "flex flex-row justify-end gap-3"
      : buttonLayout === "space-between"
      ? "flex flex-row justify-between gap-3"
      : "flex flex-row gap-3";

  return (
    <Form {...form}>
      <form
        onSubmit={(e) => {
          e.preventDefault();

          const submitter = (e.nativeEvent as SubmitEvent)
            .submitter as HTMLButtonElement | null;

          const buttonKey = submitter?.name ?? null;

          // UI only (loading state)
          setActiveButton(buttonKey);

          // ✅ pass buttonKey directly
          form.handleSubmit(handleSubmit(buttonKey))();
        }}
        className={className}
        noValidate
      >
        <div className="space-y-8">
          {sections.map((section, idx) => (
            <section key={idx} className="space-y-4">
              {section.title && (
                <h3 className="text-lg font-semibold">{section.title}</h3>
              )}
              {section.description && (
                <p className="text-sm text-muted-foreground">
                  {section.description}
                </p>
              )}
              <div
                className={getSectionLayoutClass(
                  section.layout,
                  section.columns
                )}
              >
                {section.fields.map((field) => (
                  <DynamicFormField
                    key={field.name}
                    control={form.control}
                    {...field}
                  />
                ))}
              </div>
            </section>
          ))}

          {recaptcha && <ReCAPTCHAComponent onVerify={setCaptchaToken} />}

          <FieldSeparator className="mb-2" />

          <div
            className={
              buttonLayout === "stack"
                ? "flex flex-col gap-3"
                : "flex flex-row gap-3 justify-end"
            }
          >
            <div className={buttonLayoutClass}>
              {Object.entries(buttons).map(([key, btn]) => {
                const isLoading = isSubmitting && activeButton === key;

                return (
                  <Button
                    key={key}
                    name={key}
                    type={btn.submit ? "submit" : "button"}
                    variant={btn.variant ?? "default"}
                    disabled={isSubmitting}
                    className={cn(
                      "w-full flex items-center justify-center gap-2 cursor-pointer",
                      btn.className
                    )}
                  >
                    {isLoading ? (
                      btn.loadingLabel ?? "Processing..."
                    ) : (
                      <span className="flex items-center gap-2">
                        {btn.iconLeft}
                        {btn.label}
                      </span>
                    )}
                  </Button>
                );
              })}
            </div>
          </div>
        </div>
      </form>
    </Form>
  );
}

import type {
  FieldPath,
  FieldValues,
  UseFormReturn,
  DefaultValues,
} from "react-hook-form";
import type { ReactNode } from "react";
import type { ZodType } from "zod";
import { FormFieldType } from "@/components/forms/form-field";

export type CRUDFormType = "CREATE" | "UPDATE" | "VIEW";

export type SectionLayout =
  | "stack"
  | "grid"
  | "grid-2"
  | "grid-3"
  | "grid-4"
  | "grid-6"
  | "auto-fit";

export type ButtonLayout = "stack" | "inline" | "right" | "space-between";

export interface FormBuilderField<T extends FieldValues> {
  name: FieldPath<T>;
  fieldType: FormFieldType;
  label?: string;
  placeholder?: string;
  description?: string;
  required?: boolean;
  disabled?: boolean;
  height?: "sm" | "md" | "lg" | "xl" | "auto";
  prefix?: ReactNode;
  suffix?: ReactNode;
  data?: Record<string, unknown>[];
  labelKey?: string;
  valueKey?: string;
  selectLabelKey?: string;
  mask?: string;
  maskPlaceholder?: string;
  className?: string;
  hideLabel?: boolean;
  hideDescription?: boolean;
  hideMessage?: boolean;
  wrapperClassName?: string;
  inputClassName?: string;
  labelClassName?: string;
  descriptionClassName?: string;
  messageClassName?: string;
}

export interface FormBuilderSection<T extends FieldValues> {
  title?: string;
  description?: string;
  layout?: SectionLayout;
  columns?: number; // 👈 needed for "grid"
  fields: FormBuilderField<T>[];
}

export interface FormBuilderButton<T extends FieldValues> {
  label: string;
  submit?: boolean;
  className?: string;
  loadingLabel?: string;
  variant?: "default" | "secondary" | "destructive" | "outline" | "ghost";
  iconLeft?: ReactNode;
  iconRight?: ReactNode;
  onSubmit?: (values: T, form: UseFormReturn<T>) => void | Promise<void>;
}

export interface FormBuilderStandardProps<T extends FieldValues> {
  schema: ZodType<T>;
  defaultValues: DefaultValues<T>;
  formType?: CRUDFormType;
  sections: FormBuilderSection<T>[];
  buttons: Record<string, FormBuilderButton<T>>;
  buttonLayout?: ButtonLayout;
  recaptcha?: boolean;
  className?: string;
}

import { toast } from "sonner";
import { CheckCircle2, XCircle, Info } from "lucide-react";
import { cn } from "@/lib/utils";

const baseClass =
  "flex items-start gap-3 max-w-[420px] whitespace-pre-line break-words text-sm leading-snug p-4 rounded-lg shadow-sm";

interface ToastOptions {
  message: string;
  description?: string;
  icon?: React.ReactNode;
  className?: string;
 
}

export function showSuccess({ message, description, icon, className }: ToastOptions) {
  toast.success(message, {
    icon: icon ?? (
      <CheckCircle2 className="w-5 h-5 text-green-600 shrink-0 mt-0.5" />
    ),
    description: description,
    className: cn(`${baseClass} bg-green-50 text-green-700 border border-green-200`, className),
  });
}


export function showError({ message, description, icon, className }: ToastOptions) {
  toast.error(message, {
    icon: icon ?? (
    <XCircle className="w-5 h-5 text-red-500 shrink-0 mt-0.5" />
    ),
    description: description,
    className: cn(`${baseClass} bg-red-50 text-red-700 border border-red-200`, className),
  });
}



export function showInfo(message: string) {
  toast(message, {
    icon: <Info className="w-5 h-5 text-blue-500 shrink-0 mt-0.5" />,
    className: `${baseClass} bg-blue-50 text-blue-700 border border-blue-200`,
  });
}

import { z } from "zod";
import { zodResolver } from "@hookform/resolvers/zod";
import type { FieldValues, Resolver } from "react-hook-form";

/**
 * Typed wrapper around zodResolver.
 * This keeps your FormBuilder generics clean and avoids resolver type errors.
 */
export function typedZodResolver<TValues extends FieldValues>(
  schema: z.ZodType<TValues>
): Resolver<TValues> {
  // We cast through unknown because zodResolver’s internal types are broader
  
  return zodResolver(schema as never) as unknown as Resolver<TValues>;
}
